/* Chart.js placeholder — run vendor_assets.py to replace with real file */
/* If this file is present, the CDN fallback will not be loaded. */
/* This placeholder provides a minimal Chart stub so the UI doesn't crash. */
(function(){
  if(typeof Chart !== 'undefined') return;
  function Chart(el, cfg){
    this._cfg = cfg;
    if(el && el.getContext){
      var ctx = el.getContext('2d');
      if(ctx){
        ctx.fillStyle = 'rgba(30,50,80,0.08)';
        ctx.fillRect(0,0,el.width,el.height);
        ctx.fillStyle = '#4a6fa5';
        ctx.font = '11px system-ui';
        ctx.textAlign = 'center';
        ctx.fillText('Chart.js wird geladen…', el.width/2, el.height/2);
      }
    }
  }
  Chart.prototype.destroy = function(){};
  Chart.prototype.update = function(){};
  Chart.register = function(){};
  Chart.defaults = { responsive: true, animation: false };
  window.Chart = Chart;
})();
